import{_ as o,o as a,c as s,a0 as t}from"./chunks/framework.BjpW4enL.js";const m=JSON.parse('{"title":"ADR-0029: MCP-First Expansion — Wave 3 do Cognitive Leap","description":"","frontmatter":{},"headers":[],"relativePath":"20_Arquitetura/adr/0029-mcp-first-expansion-wave3.md","filePath":"20_Arquitetura/adr/0029-mcp-first-expansion-wave3.md","lastUpdated":1783623176000}'),i={name:"20_Arquitetura/adr/0029-mcp-first-expansion-wave3.md"};function n(r,e,d,c,l,u){return a(),s("div",null,[...e[0]||(e[0]=[t(`<h1 id="adr-0029-mcp-first-expansion-—-wave-3-do-cognitive-leap" tabindex="-1">ADR-0029: MCP-First Expansion — Wave 3 do Cognitive Leap <a class="header-anchor" href="#adr-0029-mcp-first-expansion-—-wave-3-do-cognitive-leap" aria-label="Permalink to &quot;ADR-0029: MCP-First Expansion — Wave 3 do Cognitive Leap&quot;">​</a></h1><h2 id="status" tabindex="-1">Status <a class="header-anchor" href="#status" aria-label="Permalink to &quot;Status&quot;">​</a></h2><p>Aceito</p><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>A Wave 2 do Cognitive Leap estabilizou o pipeline de ingestão, controle de recursos e o grafo T4 multi-relacional. Com o motor de consulta estável e a travessia BFS (54-01) já implementada no engine REST (<code>handle_query</code>), o próximo passo natural é expor essas capacidades através do <strong>servidor MCP</strong>, que é a interface primária de agentes com o NEXUS.</p><p>O ecossistema possui <strong>dois servidores MCP</strong>:</p><ol><li><strong>Python</strong> (<code>scripts/nexus_mcp_server.py</code>) — ativo em produção, integrado ao <code>compose.yaml</code>, com 8 ferramentas registradas (<code>nexus_guide</code>, <code>nexus_query</code>, <code>nexus_map</code>, <code>nexus_admin</code>, <code>nexus_reflections</code>, <code>nexus_adjacent</code>, <code>nexus_link</code>, <code>nexus_validate_link</code>).</li><li><strong>Rust</strong> (<code>services/mcp-server/src/</code>) — servidor secundário, com menos ferramentas implementadas, atualmente sem deploy ativo.</li></ol><p>Todas as ferramentas MCP do Wave 3 (query BFS, versions, diff, stigmergy) EXPANDEM o servidor Python, que é o ponto de integração real. O servidor Rust será alinhado posteriormente.</p><h2 id="decision-drivers" tabindex="-1">Decision Drivers <a class="header-anchor" href="#decision-drivers" aria-label="Permalink to &quot;Decision Drivers&quot;">​</a></h2><ul><li><strong>Agentes usam MCP como porta de entrada</strong> — toda nova capacidade precisa ser exposta via MCP</li><li><strong>Python MCP é o ativo em produção</strong> — expandir ele primeiro, Rust em seguida</li><li><strong>54-01 (BFS query) já está no engine</strong> — precisa só do schema no MCP para ser usável</li><li><strong>T6 Versioning já tem handlers HTTP</strong> (<code>handle_versions</code> em <code>query.rs</code>) — precisa de ponte MCP</li><li><strong>Stigmergy (<code>nexus_link</code>, <code>nexus_validate_link</code>)</strong> — já implementados no Python MCP, mas não estão documentados no <code>nexus_mcp_stigmergy</code> com validação completa</li></ul><h2 id="decisao" tabindex="-1">Decisão <a class="header-anchor" href="#decisao" aria-label="Permalink to &quot;Decisão&quot;">​</a></h2><p>Adotar a estratégia <strong>MCP-First</strong> para todas as entregas da Wave 3:</p><ol><li><strong>54-04</strong> — <code>agent-stigmergy-mcp</code>: JÁ FEITO no Python MCP (tools 7 e 8). Validar que <code>nexus_link</code> e <code>nexus_validate_link</code> estão funcionais no runtime.</li><li><strong>54-05</strong> — <code>mcp-query-bfs-schema</code>: Estender a tool <code>nexus_query</code> no Python MCP para aceitar <code>subgraph_depth</code>, <code>min_energy</code> e <code>allowed_relations</code>. O argumento é passado via query string para o engine REST (<code>GET /query</code>).</li><li><strong>54-06</strong> — <code>mcp-versions-tool</code>: Implementar tool <code>nexus_versions</code> no Python MCP que chama o handler HTTP <code>POST /versions</code> do engine Rust.</li><li><strong>54-07</strong> — <code>mcp-diff-tool</code>: Implementar tool <code>nexus_diff</code> no Python MCP que chama o handler HTTP do engine (ou computa diff localmente via <code>difflib</code>/<code>unified_diff</code>).</li><li><strong>54-02</strong> — <code>l3-synthesis-completion</code>: Validar L3 no banco via <code>nexus_reflections</code> tool (já existe).</li><li><strong>54-08</strong> — <code>reflect-quality-gate-fix</code>: Aprimorar filtro no engine Rust, independente do MCP.</li><li><strong>54-03</strong> — <code>semantic-bridge-calibration</code>: Calibrar thresholds no engine, pós-entrega MCP.</li></ol><p>O servidor Rust (<code>services/mcp-server/</code>) será alinhado após a entrega do Python.</p><h2 id="consequencias" tabindex="-1">Consequências <a class="header-anchor" href="#consequencias" aria-label="Permalink to &quot;Consequências&quot;">​</a></h2><h3 id="positivas" tabindex="-1">Positivas <a class="header-anchor" href="#positivas" aria-label="Permalink to &quot;Positivas&quot;">​</a></h3><ul><li>Agentes ganham acesso imediato a BFS query, versionamento e diff via MCP</li><li>Aproveita a base Python já em produção — mudanças testáveis imediatamente</li><li>Separa preocupações: Python para integração agente, Rust para performance crítica</li><li><code>nexus_query</code> com subgrafo enriquece o contexto retornado aos agentes</li></ul><h3 id="negativas" tabindex="-1">Negativas <a class="header-anchor" href="#negativas" aria-label="Permalink to &quot;Negativas&quot;">​</a></h3><ul><li>Duas bases MCP para manter (Python + Rust) até alinhamento</li><li>Servidor Python faz chamadas HTTP para o engine Rust — latência extra</li><li>Ferramentas <code>nexus_versions</code> e <code>nexus_diff</code> dependem do engine estar ativo</li></ul><h3 id="riscos" tabindex="-1">Riscos <a class="header-anchor" href="#riscos" aria-label="Permalink to &quot;Riscos&quot;">​</a></h3><ul><li>Schema do <code>nexus_query</code> pode crescer demais — mitigação: versionar o schema</li><li>Engine Rust pode não ter endpoints para todas as tools — mitigação: implementar no Python primeiro, depois criar endpoints ausentes no Rust</li></ul><h2 id="implementacao" tabindex="-1">Implementação <a class="header-anchor" href="#implementacao" aria-label="Permalink to &quot;Implementação&quot;">​</a></h2><h3 id="ordem-de-execucao" tabindex="-1">Ordem de Execução <a class="header-anchor" href="#ordem-de-execucao" aria-label="Permalink to &quot;Ordem de Execução&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>54-05 (mcp-query-bfs-schema) → 54-04 (validação stigmergy)</span></span>
<span class="line"><span>→ 54-06 (mcp-versions-tool) → 54-07 (mcp-diff-tool)</span></span>
<span class="line"><span>→ 54-08 (reflect-quality-gate) → 54-02 (L3 validation)</span></span>
<span class="line"><span>→ 54-03 (semantic-bridge)</span></span></code></pre></div><h3 id="arquivos-afetados" tabindex="-1">Arquivos Afetados <a class="header-anchor" href="#arquivos-afetados" aria-label="Permalink to &quot;Arquivos Afetados&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Arquivo</th><th>Task</th><th>Mudança</th></tr></thead><tbody><tr><td><code>scripts/nexus_mcp_server.py</code></td><td>54-04/05/06/07</td><td>Expandir tools <code>nexus_query</code>, adicionar <code>nexus_versions</code>, <code>nexus_diff</code></td></tr><tr><td><code>services/coordinator/src/query.rs</code></td><td>54-05/06</td><td>Endpoints <code>/query</code> e <code>/versions</code> já existem</td></tr><tr><td><code>services/coordinator/src/validate.rs</code></td><td>54-04</td><td>Já implementado</td></tr><tr><td><code>.hive/features/54_nexus-cognitive-leap/plan.md</code></td><td>Todas</td><td>Atualizar status</td></tr></tbody></table><h2 id="referencias" tabindex="-1">Referências <a class="header-anchor" href="#referencias" aria-label="Permalink to &quot;Referências&quot;">​</a></h2><ul><li>Feature 54 plan: <code>.hive/features/54_nexus-cognitive-leap/plan.md</code></li><li>ADR-0022: Fechamento do audit de implementação</li><li>Código do MCP Python: <code>scripts/nexus_mcp_server.py</code></li><li>Handlers HTTP do engine: <code>services/coordinator/src/query.rs</code></li></ul>`,28)])])}const h=o(i,[["render",n]]);export{m as __pageData,h as default};
